type QuoteStep = { op: "quote"; items: unknown[] };
type ClaimStep = { op: "claim" };
type Step = QuoteStep | ClaimStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

type QuoteResult = { premium: number };
type ClaimResult = Record<string, never>;
type StepResult = QuoteResult | ClaimResult;

const processQuote = (_step: QuoteStep): QuoteResult => ({ premium: 115 });

const processStep = (step: Step): StepResult =>
  step.op === "quote" ? processQuote(step) : {};

export const runScenario = (scenario: Scenario): { results: StepResult[] } => ({
  results: scenario.steps.map(processStep),
});

type Step = { op: "quote"; items: unknown[] } | { op: "claim" };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const processStep = (step: Step): unknown =>
  step.op === "quote" ? { premium: 115 } : {};

export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
  results: scenario.steps.map(processStep),
});
